// The synthetic ensures has the implicational form `H ==> det_equal`,
// where `H` is the long conjunction of every per-run ensures-projection
// of the original function (replicated for `post1_self_` and `post2_self_`)
// and `det_equal(r1, r2, post1_self_, post2_self_)` is
// `(r1 == r2) && (post1_self_ == post2_self_)`.
//
// `H` is the antecedent of the postcondition's implication, so it is
// NOT a free hypothesis at the prelude position — Verus only assumes
// the antecedent when discharging the implication at function exit.
// To make `H` usable as a hypothesis during the derivation, wrap the
// derivation in `if (H) { ... }`. Inside the branch every conjunct of
// `H` is in scope; any `assert(Q)` proved there is remembered by Verus
// (path-sensitively) as `H ==> Q` outside the branch. That is exactly
// what is needed to discharge `H ==> det_equal` at function exit.
//
// The previous attempt asserted that the full `Option<PageTable>` at
// `ioid` was `=~=`-equal across the two runs. That step is structurally
// impossible from the spec alone — the ensures only pin a small set of
// observable projections of `PageTable` (`ioid`, `kernel_l4_end`,
// `page_closure()`, `mapping_*()`, `spec_resolve_mapping_*()`,
// `kernel_entries`), while the struct itself contains many unpinned
// fields (`cr3`, `pcid`, `l4_table`, `l3_tables`, `l2_tables`,
// `l1_tables`, `tlb_mapping_*`, the rev-maps). Asserting unprovable
// equalities makes Verus give up with extra noise, so we restrict the
// derivation to facts that ARE forced by `H`: (a) per-index equality
// at every non-`ioid` slot of the `Array`, chained through
// `pre_self_@[p as int]`, and (b) per-projection equality at the
// `ioid` slot, also chained through `pre_self_@[ioid as int].unwrap()`.
if ({
    &&& post1_self_.wf()
    &&& post2_self_.wf()
    &&& (forall|p: IOid|
        #![trigger post1_self_@[p as int]]
        #![trigger pre_self_@[p as int]]
        0 <= p < IOID_MAX && p != ioid ==> post1_self_@[p as int] =~= pre_self_@[p as int])
    &&& (forall|p: IOid|
        #![trigger post2_self_@[p as int]]
        #![trigger pre_self_@[p as int]]
        0 <= p < IOID_MAX && p != ioid ==> post2_self_@[p as int] =~= pre_self_@[p as int])
    &&& post1_self_@[ioid as int].is_Some()
    &&& post2_self_@[ioid as int].is_Some()
    &&& post1_self_@[ioid as int].unwrap().ioid == pre_self_@[ioid as int].unwrap().ioid
    &&& post2_self_@[ioid as int].unwrap().ioid == pre_self_@[ioid as int].unwrap().ioid
    &&& post1_self_@[ioid as int].unwrap().kernel_l4_end == pre_self_@[ioid as int].unwrap().kernel_l4_end
    &&& post2_self_@[ioid as int].unwrap().kernel_l4_end == pre_self_@[ioid as int].unwrap().kernel_l4_end
    &&& post1_self_@[ioid as int].unwrap().page_closure()
            =~= pre_self_@[ioid as int].unwrap().page_closure().insert(page_map_ptr)
    &&& post2_self_@[ioid as int].unwrap().page_closure()
            =~= pre_self_@[ioid as int].unwrap().page_closure().insert(page_map_ptr)
    &&& post1_self_@[ioid as int].unwrap().mapping_4k()
            =~= pre_self_@[ioid as int].unwrap().mapping_4k()
    &&& post2_self_@[ioid as int].unwrap().mapping_4k()
            =~= pre_self_@[ioid as int].unwrap().mapping_4k()
    &&& post1_self_@[ioid as int].unwrap().mapping_2m()
            =~= pre_self_@[ioid as int].unwrap().mapping_2m()
    &&& post2_self_@[ioid as int].unwrap().mapping_2m()
            =~= pre_self_@[ioid as int].unwrap().mapping_2m()
    &&& post1_self_@[ioid as int].unwrap().mapping_1g()
            =~= pre_self_@[ioid as int].unwrap().mapping_1g()
    &&& post2_self_@[ioid as int].unwrap().mapping_1g()
            =~= pre_self_@[ioid as int].unwrap().mapping_1g()
    &&& post1_self_@[ioid as int].unwrap().spec_resolve_mapping_1g_l3(target_l4i, target_l3i)
            == pre_self_@[ioid as int].unwrap().spec_resolve_mapping_1g_l3(target_l4i, target_l3i)
    &&& post2_self_@[ioid as int].unwrap().spec_resolve_mapping_1g_l3(target_l4i, target_l3i)
            == pre_self_@[ioid as int].unwrap().spec_resolve_mapping_1g_l3(target_l4i, target_l3i)
    &&& post1_self_@[ioid as int].unwrap().spec_resolve_mapping_l3(target_l4i, target_l3i)
            == pre_self_@[ioid as int].unwrap().spec_resolve_mapping_l3(target_l4i, target_l3i)
    &&& post2_self_@[ioid as int].unwrap().spec_resolve_mapping_l3(target_l4i, target_l3i)
            == pre_self_@[ioid as int].unwrap().spec_resolve_mapping_l3(target_l4i, target_l3i)
    &&& post1_self_@[ioid as int].unwrap().spec_resolve_mapping_l2(target_l4i, target_l3i, target_l2i).is_Some()
    &&& post2_self_@[ioid as int].unwrap().spec_resolve_mapping_l2(target_l4i, target_l3i, target_l2i).is_Some()
    &&& post1_self_@[ioid as int].unwrap().spec_resolve_mapping_l2(target_l4i, target_l3i, target_l2i).get_Some_0().addr
            == page_map_ptr
    &&& post2_self_@[ioid as int].unwrap().spec_resolve_mapping_l2(target_l4i, target_l3i, target_l2i).get_Some_0().addr
            == page_map_ptr
    &&& post1_self_@[ioid as int].unwrap().spec_resolve_mapping_2m_l2(target_l4i, target_l3i, target_l2i).is_None()
    &&& post2_self_@[ioid as int].unwrap().spec_resolve_mapping_2m_l2(target_l4i, target_l3i, target_l2i).is_None()
    &&& post1_self_@[ioid as int].unwrap().kernel_entries
            =~= pre_self_@[ioid as int].unwrap().kernel_entries
    &&& post2_self_@[ioid as int].unwrap().kernel_entries
            =~= pre_self_@[ioid as int].unwrap().kernel_entries
}) {
    // Close the disjoint-trigger gap on the two per-run `forall|p|`s:
    // each side's quantifier fires on the *same* `p` through the shared
    // `pre_self_@[p as int]` trigger, so chain them through `pre` to
    // get a single post-vs-post equality at every non-`ioid` slot.
    assert forall|p: IOid|
        0 <= p < IOID_MAX && p != ioid
    implies
        post1_self_@[p as int] =~= post2_self_@[p as int]
    by {
        assert(post1_self_@[p as int] =~= pre_self_@[p as int]);
        assert(post2_self_@[p as int] =~= pre_self_@[p as int]);
    };

    // Per-projection equalities at the `ioid` slot, each chained through
    // `pre_self_@[ioid as int].unwrap()` (so post1 and post2 line up
    // exactly on every projection the spec actually pins down).
    assert(post1_self_@[ioid as int].unwrap().ioid
        == post2_self_@[ioid as int].unwrap().ioid);
    assert(post1_self_@[ioid as int].unwrap().kernel_l4_end
        == post2_self_@[ioid as int].unwrap().kernel_l4_end);
    assert(post1_self_@[ioid as int].unwrap().page_closure()
        =~= post2_self_@[ioid as int].unwrap().page_closure());
    assert(post1_self_@[ioid as int].unwrap().mapping_4k()
        =~= post2_self_@[ioid as int].unwrap().mapping_4k());
    assert(post1_self_@[ioid as int].unwrap().mapping_2m()
        =~= post2_self_@[ioid as int].unwrap().mapping_2m());
    assert(post1_self_@[ioid as int].unwrap().mapping_1g()
        =~= post2_self_@[ioid as int].unwrap().mapping_1g());
    assert(post1_self_@[ioid as int].unwrap()
            .spec_resolve_mapping_1g_l3(target_l4i, target_l3i)
        == post2_self_@[ioid as int].unwrap()
            .spec_resolve_mapping_1g_l3(target_l4i, target_l3i));
    assert(post1_self_@[ioid as int].unwrap()
            .spec_resolve_mapping_l3(target_l4i, target_l3i)
        == post2_self_@[ioid as int].unwrap()
            .spec_resolve_mapping_l3(target_l4i, target_l3i));
    assert(post1_self_@[ioid as int].unwrap()
            .spec_resolve_mapping_l2(target_l4i, target_l3i, target_l2i).is_Some());
    assert(post2_self_@[ioid as int].unwrap()
            .spec_resolve_mapping_l2(target_l4i, target_l3i, target_l2i).is_Some());
    assert(post1_self_@[ioid as int].unwrap()
            .spec_resolve_mapping_l2(target_l4i, target_l3i, target_l2i).get_Some_0().addr
        == post2_self_@[ioid as int].unwrap()
            .spec_resolve_mapping_l2(target_l4i, target_l3i, target_l2i).get_Some_0().addr);
    assert(post1_self_@[ioid as int].unwrap()
            .spec_resolve_mapping_2m_l2(target_l4i, target_l3i, target_l2i).is_None());
    assert(post2_self_@[ioid as int].unwrap()
            .spec_resolve_mapping_2m_l2(target_l4i, target_l3i, target_l2i).is_None());
    assert(post1_self_@[ioid as int].unwrap().kernel_entries
        =~= post2_self_@[ioid as int].unwrap().kernel_entries);

    // Lengths of the two array views are both PCID_MAX via `wf()`.
    assert(post1_self_@.len() == PCID_MAX as int);
    assert(post2_self_@.len() == PCID_MAX as int);
}

// Returns are `()`, trivially equal — record this so the `r1 == r2`
// conjunct of `det_equal` is visibly discharged.
assert(r1 == r2);
